import { PDFDocument, rgb, StandardFonts } from 'pdf-lib';

async function hashPassword(password) {
    const encoder = new TextEncoder();
    const data = encoder.encode(password + "MediUnit_S4L7_2026!");
    const hash = await crypto.subtle.digest('SHA-256', data);
    return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2, '0')).join('');
}

async function isRateLimited(env, ip, limit, windowSeconds, keyPrefix) {
    if (!env.LIMITER) return false;
    const now = Math.floor(Date.now() / 1000);
    const windowStart = now - windowSeconds;
    const key = `rl:${keyPrefix}:${ip}`;

    let logs = await env.LIMITER.get(key, { type: 'json' }) || [];
    logs = logs.filter(timestamp => timestamp > windowStart);

    if (logs.length >= limit) return true;

    logs.push(now);
    await env.LIMITER.put(key, JSON.stringify(logs), { expirationTtl: windowSeconds });
    return false;
}

async function sendEmail(env, { to, subject, html }) {
    if (!env.RESEND_API_KEY) {
        console.warn("RESEND_API_KEY missing, skipping email.");
        return;
    }
    await fetch("https://api.resend.com/emails", {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${env.RESEND_API_KEY}`
        },
        body: JSON.stringify({
            from: "MediUnit <orders@mediunit.ma>",
            to,
            subject,
            html
        })
    });
}

export default {
    async fetch(request, env) {
        const corsHeaders = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type",
        };

        if (request.method === "OPTIONS") {
            return new Response(null, { headers: corsHeaders });
        }

        try {
            const url = new URL(request.url);
            const path = url.pathname;

            if (path.startsWith("/api/v1/images/")) {
                let key = path.replace("/api/v1/images/", "");
                try {
                    // Try to decode URI component in case it's url-encoded
                    key = decodeURIComponent(key);
                    const object = await env.STORAGE.get(key);
                    if (!object) {
                        return new Response("Image not found", { status: 404, headers: corsHeaders });
                    }
                    const headers = new Headers();
                    object.writeHttpMetadata(headers);
                    headers.set("etag", object.httpEtag);

                    // Fallback content-type if missing
                    if (!headers.has("content-type")) {
                        const ext = key.split('.').pop()?.toLowerCase();
                        let cType = "image/jpeg";
                        if (ext === "png") cType = "image/png";
                        if (ext === "svg") cType = "image/svg+xml";
                        headers.set("content-type", cType);
                    }

                    headers.set("Cache-Control", "public, max-age=31536000, immutable");
                    for (const [k, v] of Object.entries(corsHeaders)) {
                        headers.set(k, v);
                    }
                    return new Response(object.body, { headers });
                } catch (err) {
                    return new Response("Error fetching image", { status: 500, headers: corsHeaders });
                }
            }

            if (path === "/api/v1/categories") {
                const { results } = await env.DB.prepare("SELECT * FROM category").all();
                return new Response(JSON.stringify(results), {
                    headers: { "Content-Type": "application/json", ...corsHeaders }
                });
            }

            if (path === "/api/v1/brands") {
                const { results } = await env.DB.prepare("SELECT * FROM brand").all();
                return new Response(JSON.stringify(results), {
                    headers: { "Content-Type": "application/json", ...corsHeaders }
                });
            }

            if (path === "/api/v1/products") {
                const categorySlug = url.searchParams.get("category_slug");
                const search = url.searchParams.get("search");

                let sql = "SELECT p.*, c.name as category_name, c.slug as category_slug, b.name as brand_name FROM product p " +
                    "LEFT JOIN category c ON p.category_id = c.id " +
                    "LEFT JOIN brand b ON p.brand_id = b.id WHERE 1=1";
                const args = [];

                if (categorySlug) {
                    sql += " AND c.slug = ?";
                    args.push(categorySlug);
                }
                if (search) {
                    sql += " AND (p.name LIKE ? OR p.sku LIKE ?)";
                    args.push(`%${search}%`, `%${search}%`);
                }
                sql += " ORDER BY p.popularity DESC LIMIT 100";

                const { results } = await env.DB.prepare(sql).bind(...args).all();
                const formatted = results.map(r => ({
                    ...r,
                    category: { name: r.category_name || "N/A", slug: r.category_slug || "" }
                }));

                return new Response(JSON.stringify(formatted), {
                    headers: { "Content-Type": "application/json", ...corsHeaders }
                });
            }

            if (path.startsWith("/api/v1/products/")) {
                const parts = path.split("/");
                const slug = parts[4]; // /api/v1/products/[slug]

                if (parts[5] === "spec-pdf") {
                    const urlObj = new URL(request.url);
                    const lang = urlObj.searchParams.get('lang') || 'fr';
                    const t = (fr, en) => lang === 'en' ? en : fr;

                    const product = await env.DB.prepare(`
                        SELECT p.*, c.name as category_name, b.name as brand_name, b.manufacturer 
                        FROM product p 
                        LEFT JOIN category c ON p.category_id = c.id 
                        LEFT JOIN brand b ON p.brand_id = b.id 
                        WHERE p.slug = ?
                    `).bind(slug).first();

                    if (!product) return new Response("Not Found", { status: 404, headers: corsHeaders });

                    const cacheKey = `spec-pdf-${slug}-${lang}.pdf`;
                    try {
                        const cachedPdf = await env.STORAGE.get(cacheKey);
                        if (cachedPdf) {
                            return new Response(cachedPdf.body, {
                                headers: {
                                    "Content-Type": "application/pdf",
                                    "Content-Disposition": `inline; filename="${t('Fiche_Technique', 'Technical_Sheet')}_${slug}.pdf"`,
                                    ...corsHeaders
                                }
                            });
                        }
                    } catch (e) { console.error("R2 cache config error", e); }

                    try {
                        const pdfDoc = await PDFDocument.create();
                        const logoImageBytes = Uint8Array.from(atob(``), c => c.charCodeAt(0));
                        const logoImage = await pdfDoc.embedPng(logoImageBytes);
                        const logoDims = logoImage.scale(0.08);
                        const fontBold = await pdfDoc.embedFont(StandardFonts.HelveticaBold);
                        const fontRegular = await pdfDoc.embedFont(StandardFonts.Helvetica);

                        const primaryColor = rgb(0.04, 0.15, 0.25); // Premium MediUnit Dark Slate Blue
                        const softTeal = rgb(0.12, 0.54, 0.51); // MediUnit Teal
                        const grayColor = rgb(0.4, 0.4, 0.4);
                        const lightGray = rgb(0.95, 0.96, 0.98);

                        let page = pdfDoc.addPage([595.28, 841.89]);
                        const { width, height } = page.getSize();

                        // Header with Logo
                        page.drawImage(logoImage, {
                            x: 40,
                            y: height - 80,
                            width: logoDims.width,
                            height: logoDims.height,
                        });

                        // Header Contact Info (Opposite side)
                        page.drawText('MediUnit - Excellence Clinique', { x: width - 200, y: height - 40, size: 10, font: fontBold, color: primaryColor });
                        page.drawText('Contact: +212 661 36 43 75', { x: width - 200, y: height - 55, size: 9, font: fontRegular, color: grayColor });
                        page.drawText('Email: support@mediunit.ma', { x: width - 200, y: height - 70, size: 9, font: fontRegular, color: grayColor });

                        // Subtle header separating line
                        page.drawLine({ start: { x: 40, y: height - 100 }, end: { x: width - 40, y: height - 100 }, thickness: 1, color: softTeal });

                        // Main Premium Title Block
                        page.drawRectangle({ x: 40, y: height - 150, width: width - 80, height: 35, color: lightGray });
                        page.drawText(t('FICHE TECHNIQUE & SPÉCIFICATIONS', 'TECHNICAL DATA SHEET & SPECIFICATIONS'), { x: 55, y: height - 138, size: 14, font: fontBold, color: primaryColor });

                        let yPos = height - 180;

                        const checkNewPage = (neededSpace = 60) => {
                            if (yPos < neededSpace) {
                                page = pdfDoc.addPage([595.28, 841.89]);
                                yPos = height - 60;
                            }
                        };

                        const drawSectionTitle = (title) => {
                            checkNewPage(40);
                            page.drawText(title, { x: 40, y: yPos, size: 12, font: fontBold, color: primaryColor });
                            page.drawLine({ start: { x: 40, y: yPos - 5 }, end: { x: width - 40, y: yPos - 5 }, thickness: 0.5, color: rgb(0.8, 0.8, 0.8) });
                            yPos -= 25;
                        };

                        const drawBulletPoint = (label, value) => {
                            checkNewPage(20);
                            page.drawText('▸', { x: 45, y: yPos, size: 10, font: fontBold, color: softTeal });
                            page.drawText(label, { x: 60, y: yPos, size: 10, font: fontBold, color: primaryColor });

                            const valStr = String(value || 'N/A');
                            const labelWidth = fontBold.widthOfTextAtSize(label, 10);
                            const safeValStr = valStr.replace(/[^A-Za-z0-9 .,/()\-:;'"]/g, '').substring(0, 100);

                            page.drawText(safeValStr, { x: 65 + labelWidth, y: yPos, size: 10, font: fontRegular, color: grayColor });
                            yPos -= 18;
                        };

                        // Section 1: Informations Générales
                        drawSectionTitle(t('1. Informations d\'Identification', '1. Identification Information'));
                        drawBulletPoint(t('Marque :', 'Brand :'), product.brand_name || 'MediUnit Standard');
                        drawBulletPoint(t('Désignation :', 'Designation :'), product.name);
                        drawBulletPoint('SKU :', product.sku);
                        drawBulletPoint(t('Catégorie :', 'Category :'), product.category_name || t('Consommable', 'Consumable'));

                        yPos -= 10;

                        // Section 2: Caractéristiques Techniques
                        drawSectionTitle(t('2. Caractéristiques Techniques', '2. Technical Characteristics'));
                        let specParsed = {};
                        try {
                            if (product.specifications) {
                                specParsed = typeof product.specifications === 'string' ? JSON.parse(product.specifications) : product.specifications;
                            }
                        } catch (e) { }

                        for (const [key, value] of Object.entries(specParsed)) {
                            if (['marque', 'fabricant', 'sku', 'brand', 'manufacturer'].includes(key.toLowerCase())) continue;
                            const label = key.charAt(0).toUpperCase() + key.slice(1).replace(/_/g, ' ') + ' :';
                            drawBulletPoint(label, Array.isArray(value) ? value.join(', ') : value);
                        }

                        yPos -= 10;

                        // Section 3: Stérilisation & Conditionnement
                        drawSectionTitle(t('3. Stérilisation et Conditionnement', '3. Sterilization and Packaging'));
                        drawBulletPoint(t('Méthode :', 'Method :'), product.specifications?.includes('Stérile') ? t('Oxyde d\'éthylène (STERILE EO)', 'Ethylene Oxide (STERILE EO)') : t('Non stérile / N/A', 'Non-sterile / N/A'));
                        drawBulletPoint(t('Conditionnement :', 'Packaging :'), product.packaging_type || t('Unité', 'Unit'));

                        yPos -= 10;

                        // Section 4: Description Clinique
                        drawSectionTitle(t('4. Description Clinique', '4. Clinical Description'));

                        // Intelligent formatting: convert common block elements to real newlines, preserve accents
                        const rawDesc = String(product.description || '');
                        let cleanDesc = rawDesc
                            .replace(/<br\s*\/?>/gi, '\n')
                            .replace(/<\/p>/gi, '\n\n')
                            .replace(/<li>/gi, '\n• ')
                            .replace(/<\/li>/gi, '')
                            .replace(/<[^>]*>?/gm, '') // Strip remaining HTML
                            .replace(/&nbsp;/g, ' ')
                            .replace(/&amp;/g, '&');

                        // Split into explicit paragraphs based on newlines
                        const paragraphs = cleanDesc.split('\n');

                        for (let p of paragraphs) {
                            p = p.trim();
                            if (!p) continue; // Skip empty lines

                            const words = p.split(' ');
                            let line = '';

                            for (let n = 0; n < words.length; n++) {
                                const testLine = line + words[n] + ' ';
                                const testWidth = fontRegular.widthOfTextAtSize(testLine, 9);

                                if (testWidth > width - 100 && n > 0) {
                                    checkNewPage(20);
                                    page.drawText(line, { x: 50, y: yPos, size: 9, font: fontRegular, color: grayColor });
                                    line = words[n] + ' ';
                                    yPos -= 13;
                                } else {
                                    line = testLine;
                                }
                            }
                            // Flush the remaining line
                            checkNewPage(20);
                            page.drawText(line, { x: 50, y: yPos, size: 9, font: fontRegular, color: grayColor });
                            // Add extra spacing between completed paragraphs
                            yPos -= 18;
                        }

                        yPos -= 15;

                        // Footer
                        const footerY = 30;
                        page.drawLine({ start: { x: 40, y: footerY + 15 }, end: { x: width - 40, y: footerY + 15 }, thickness: 0.5, color: rgb(0.8, 0.8, 0.8) });
                        page.drawText(t('Généré de manière sécurisée par MediUnit Cloud Edge | https://mediunit.ma', 'Generated securely by MediUnit Cloud Edge | https://mediunit.ma'), { x: 40, y: footerY, size: 8, font: fontRegular, color: softTeal });
                        page.drawText(t('Document certifié exact à la date d\'émission', 'Document certified accurate as of the date of issue'), { x: width - 200, y: footerY, size: 8, font: fontRegular, color: rgb(0.6, 0.6, 0.6) });

                        const pdfBytes = await pdfDoc.save();

                        try {
                            await env.STORAGE.put(cacheKey, pdfBytes, {
                                httpMetadata: { contentType: "application/pdf" }
                            });
                        } catch (e) { console.error("R2 put error", e); }

                        return new Response(pdfBytes, {
                            headers: {
                                "Content-Type": "application/pdf",
                                "Content-Disposition": `inline; filename="${t('Fiche_Technique', 'Technical_Sheet')}_${slug}.pdf"`,
                                ...corsHeaders
                            }
                        });
                    } catch (pdfErr) {
                        console.error("PDF Error: ", pdfErr);
                        return new Response("Error generating PDF", { status: 500, headers: corsHeaders });
                    }
                }

                const product = await env.DB.prepare(`
          SELECT p.*, c.name as category_name, c.slug as category_slug, 
                 b.name as brand_entity_name, b.manufacturer as brand_manufacturer
          FROM product p 
          LEFT JOIN category c ON p.category_id = c.id 
          LEFT JOIN brand b ON p.brand_id = b.id 
          WHERE p.slug = ?
        `).bind(slug).first();

                if (!product) {
                    return new Response(JSON.stringify({ error: "Product not found" }), {
                        status: 404,
                        headers: { "Content-Type": "application/json", ...corsHeaders }
                    });
                }

                const formatted = {
                    ...product,
                    category: { name: product.category_name, slug: product.category_slug },
                    brand_entity: {
                        name: product.brand_entity_name || product.brand || "MediUnit",
                        manufacturer: product.brand_manufacturer
                    }
                };

                return new Response(JSON.stringify(formatted), {
                    headers: { "Content-Type": "application/json", ...corsHeaders }
                });
            }

            // --- ADMIN ROUTES ---
            const isAdminPath = path.startsWith("/api/v1/admin/") || path.startsWith("/api/v1/orders/admin") || path.startsWith("/api/v1/users");

            if (path === "/api/v1/orders/admin/all" && request.method === "GET") {
                const { results } = await env.DB.prepare("SELECT * FROM \"order\" ORDER BY created_at DESC").all();
                return new Response(JSON.stringify(results), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path === "/api/v1/users/" && request.method === "GET") {
                const { results } = await env.DB.prepare("SELECT * FROM user ORDER BY created_at DESC").all();
                return new Response(JSON.stringify(results), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path.match(/^\/api\/v1\/orders\/([^/]+)\/status$/) && request.method === "PATCH") {
                const orderId = path.split("/")[4];
                const newStatus = url.searchParams.get("status") || "pending";
                await env.DB.prepare("UPDATE \"order\" SET status = ? WHERE id = ?").bind(newStatus, orderId).run();
                return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path.match(/^\/api\/v1\/users\/([^/]+)\/verify$/) && request.method === "PATCH") {
                const userId = path.split("/")[4];
                await env.DB.prepare("UPDATE user SET verification_status = 'verified' WHERE id = ?").bind(userId).run();

                // Fetch user to send email
                const user = await env.DB.prepare("SELECT * FROM user WHERE id = ?").bind(userId).first();
                if (user && user.email) {
                    await sendEmail(env, {
                        to: user.email,
                        subject: "Compte MediUnit Approuvé ✅",
                        html: `
                            <div style="font-family: sans-serif; max-width: 600px; margin: auto; padding: 20px; border: 1px solid #eee; border-radius: 20px;">
                                <h1 style="color: #1e5999;">Félicitations !</h1>
                                <p>Bonjour ${user.full_name || 'Docteur'},</p>
                                <p>Votre compte professionnel (INPE: ${user.inpe_number || 'N/A'}) a été vérifié et approuvé par notre équipe médicale.</p>
                                <p>Vous pouvez dès à présent vous connecter sur MediUnit et accéder à notre catalogue B2B avec des tarifs préférentiels.</p>
                                <div style="text-align: center; margin: 30px 0;">
                                    <a href="https://mediunit.ma/login" style="background-color: #1e5999; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; font-weight: bold;">Accéder à mon espace</a>
                                </div>
                                <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;"/>
                                <p style="font-size: 12px; color: #666;">L'équipe MediUnit</p>
                            </div>
                        `
                    });
                }

                return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            // --- PRODUCT CRUD ---
            if (path === "/api/v1/products" && request.method === "POST") {
                const body = await request.json();
                const id = body.id || Math.floor(Math.random() * 1000000);
                const slug = body.name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
                await env.DB.prepare(`
                    INSERT INTO product (id, name, slug, sku, description, base_unit_price, popularity, stock, category_id, brand_id, specifications, packaging_type, image_url)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                `).bind(
                    id, body.name, slug, body.sku || '', body.description || '', body.base_unit_price || 0,
                    body.popularity || 0, body.stock || 100, body.category_id || 1, body.brand_id || 1,
                    body.specifications || '{}', body.packaging_type || 'Unité', body.image_url || ''
                ).run();
                return new Response(JSON.stringify({ success: true, id }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path.match(/^\/api\/v1\/products\/([^/]+)$/) && request.method === "PUT") {
                const productId = path.split("/")[4];
                const body = await request.json();
                await env.DB.prepare(`
                    UPDATE product 
                    SET name = ?, sku = ?, base_unit_price = ?, stock = ?, category_id = ?, brand_id = ?, description = ?, specifications = ?, packaging_type = ?, image_url = ?
                    WHERE id = ?
                `).bind(
                    body.name, body.sku, body.base_unit_price, body.stock,
                    body.category_id || 1, body.brand_id || 1, body.description || '',
                    body.specifications || '{}', body.packaging_type || 'Unité', body.image_url || '',
                    productId
                ).run();
                return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }


            if (path === "/api/v1/auth/login" && request.method === "POST") {
                const body = await request.json();
                const hashedPassword = await hashPassword(body.password);
                const user = await env.DB.prepare("SELECT * FROM user WHERE email = ? AND hashed_password = ?").bind(body.username, hashedPassword).first();
                if (!user) return new Response(JSON.stringify({ error: "Invalid credentials" }), { status: 401, headers: corsHeaders });
                return new Response(JSON.stringify({ token: "stub-token-" + user.id, user }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path.startsWith("/api/v1/brands/") && request.method === "PUT") {
                const brandId = path.split("/")[4];
                const body = await request.json();
                await env.DB.prepare("UPDATE brand SET name = ?, logo_url = ?, manufacturer = ?, notes = ?, ce_certificate_url = ? WHERE id = ?")
                    .bind(body.name, body.logo_url, body.manufacturer, body.notes, body.ce_certificate_url, brandId).run();
                return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path === "/api/v1/auth/register" && request.method === "POST") {
                const ip = request.headers.get("CF-Connecting-IP") || "local";
                if (await isRateLimited(env, ip, 5, 60, "register")) {
                    return new Response(JSON.stringify({ error: "Rate limit exceeded" }), { status: 429, headers: corsHeaders });
                }
                const body = await request.json();
                const id = crypto.randomUUID();

                // Store user with 'pending' status
                const hashedPassword = await hashPassword(body.password);
                await env.DB.prepare(`
                    INSERT INTO user (id, email, hashed_password, full_name, clinic_name, specialty, inpe_number, city, verification_status, created_at) 
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'pending', datetime('now'))
                `).bind(
                    id, body.email, hashedPassword, body.full_name || '',
                    body.clinic_name || '', body.specialty || '',
                    body.inpe_number || '', body.city || 'Casablanca'
                ).run();

                // Send Welcome/Confirmation Email to User
                await sendEmail(env, {
                    to: body.email,
                    subject: "Demande d'accès MediUnit - En cours de vérification",
                    html: `
                        <div style="font-family: sans-serif; max-width: 600px; margin: auto; padding: 20px; border: 1px solid #eee; border-radius: 20px;">
                            <h1 style="color: #1e5999;">Bienvenue sur MediUnit</h1>
                            <p>Bonjour ${body.full_name || 'Docteur'},</p>
                            <p>Nous avons bien reçu votre demande d'accès à la plateforme MediUnit.</p>
                            <p>Notre équipe de conformité vérifie actuellement vos informations professionnelles (INPE: ${body.inpe_number}).</p>
                            <p><strong>Vous recevrez un e-mail dès que votre compte sera activé (généralement sous 24h).</strong></p>
                            <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;"/>
                            <p style="font-size: 12px; color: #666;">MediUnit Morocco - Clinical B2B Sourcing</p>
                        </div>
                    `
                });

                // Send Alert to Admin
                await sendEmail(env, {
                    to: "abdel@mediunit.ma",
                    subject: "Nouvelle Demande d'Accès B2B - MediUnit",
                    html: `
                        <h1>Nouvelle inscription à vérifier</h1>
                        <ul>
                            <li><strong>Nom:</strong> ${body.full_name}</li>
                            <li><strong>Email:</strong> ${body.email}</li>
                            <li><strong>Clinique:</strong> ${body.clinic_name}</li>
                            <li><strong>Spécialité:</strong> ${body.specialty}</li>
                            <li><strong>INPE:</strong> ${body.inpe_number}</li>
                            <li><strong>Ville:</strong> ${body.city}</li>
                        </ul>
                        <p><a href="https://mediunit-frontend.pages.dev/admin/users">Accéder au panel admin pour valider</a></p>
                    `
                });

                return new Response(JSON.stringify({ success: true, id }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path === "/api/v1/kits") {
                const { results } = await env.DB.prepare("SELECT * FROM kit").all();
                return new Response(JSON.stringify(results), {
                    headers: { "Content-Type": "application/json", ...corsHeaders }
                });
            }

            if (path.startsWith("/api/v1/kits/")) {
                const slug = path.split("/")[4];
                const kit = await env.DB.prepare("SELECT * FROM kit WHERE slug = ?").bind(slug).first();
                if (!kit) return new Response("Not Found", { status: 404, headers: corsHeaders });

                const { results: items } = await env.DB.prepare(`
                    SELECT ki.default_quantity, p.* 
                    FROM kit_item ki 
                    JOIN product p ON ki.product_id = p.id 
                    WHERE ki.kit_id = ?
                `).bind(kit.id).all();

                return new Response(JSON.stringify({ ...kit, items }), {
                    headers: { "Content-Type": "application/json", ...corsHeaders }
                });
            }

            if (path === "/api/v1/orders/" && request.method === "POST") {
                const ip = request.headers.get("CF-Connecting-IP") || "local";
                if (await isRateLimited(env, ip, 3, 60, "orders")) {
                    return new Response(JSON.stringify({ error: "Rate limit exceeded" }), { status: 429, headers: corsHeaders });
                }
                const body = await request.json();

                // 1. Validate cart and calculate totals
                let subtotal = 0;
                let itemCount = 0;
                const itemsWithPrice = [];

                for (const item of body.items) {
                    const product = await env.DB.prepare("SELECT id, name, base_unit_price, stock FROM product WHERE id = ?").bind(item.product_id).first();

                    if (!product) {
                        return new Response(JSON.stringify({ error: `Produit introuvable: ${item.product_id}` }), { status: 400, headers: corsHeaders });
                    }
                    if (item.quantity > (product.stock || 0)) {
                        return new Response(JSON.stringify({ error: `Stock insuffisant pour ${product.name}. Disponible: ${product.stock || 0}` }), { status: 400, headers: corsHeaders });
                    }

                    const priceResult = product.base_unit_price;
                    subtotal += priceResult * item.quantity;
                    itemCount += item.quantity;
                    itemsWithPrice.push({ ...item, price: priceResult, name: product.name });
                }

                if (itemsWithPrice.length === 0) {
                    return new Response(JSON.stringify({ error: "Le panier est vide." }), { status: 400, headers: corsHeaders });
                }

                let total = subtotal;
                if (itemCount >= 50) total = subtotal * 0.8;
                else if (itemCount >= 10) total = subtotal * 0.9;

                // Add VAT 20%
                total = total * 1.20;

                // 2. Create Address and get ID
                const shipping = body.shipping_details || {};
                const addrResult = await env.DB.prepare(`
                    INSERT INTO address (first_name, last_name, phone, street_address, city, zip_code) 
                    VALUES (?, ?, ?, ?, ?, ?) RETURNING id
                `).bind(
                    shipping.first_name || body.first_name,
                    shipping.last_name || body.last_name,
                    shipping.phone || body.phone,
                    shipping.address || body.address,
                    shipping.city || body.city || 'Casablanca',
                    shipping.zip_code || body.zip_code || '20000'
                ).first();

                const addrId = addrResult.id;

                // 3. Create Order and get ID
                const orderResult = await env.DB.prepare(`
                    INSERT INTO "order" (total_amount, status, shipping_address_id, created_at) 
                    VALUES (?, 'pending', ?, datetime('now')) RETURNING id
                `).bind(total, addrId).first();

                const orderId = orderResult.id;

                // 4. Create Order Items and update stock
                let itemsListHtml = "<ul>";
                for (const item of itemsWithPrice) {
                    await env.DB.prepare(`
                        INSERT INTO order_item (order_id, product_id, quantity, price_per_unit_at_purchase, selected_variant) 
                        VALUES (?, ?, ?, ?, ?)
                    `).bind(orderId, item.product_id, item.quantity, item.price, item.variant || '').run();

                    // Deduct stock
                    await env.DB.prepare("UPDATE product SET stock = stock - ? WHERE id = ?").bind(item.quantity, item.product_id).run();

                    itemsListHtml += `<li>${item.name} (x${item.quantity}) - MAD ${item.price.toFixed(2)}</li>`;
                }
                itemsListHtml += "</ul>";

                // Send Emails
                const userEmail = shipping.email || body.email; // Fallback if email is provided
                if (userEmail) {
                    await sendEmail(env, {
                        to: userEmail,
                        subject: `Confirmation de Commande MediUnit #${orderId}`,
                        html: `
                        < div style = "font-family: sans-serif; max-width: 600px; margin: auto; padding: 20px; border: 1px solid #eee;" >
                                <h1 style="color: #1e5999;">Merci pour votre commande !</h1>
                                <p>Bonjour ${shipping.first_name || 'Client'},</p>
                                <p>Votre commande <strong>#${orderId}</strong> a bien été enregistrée et sera traitée sous 24-48h.</p>
                                <p><strong>Détails :</strong></p>
                                ${itemsListHtml}
                        < p > <strong>Total :</strong> MAD ${total.toFixed(2)}</p >
                                <p>Le paiement se fera <strong>à la livraison</strong>.</p>
                                <hr/>
                                <p style="font-size: 12px; color: #666;">MediUnit Professional - Sourcing Clinique B2B</p>
                            </div >
                            `
                    });
                }

                // Admin Notification
                await sendEmail(env, {
                    to: "abdel@mediunit.ma",
                    subject: `Nouvelle Commande B2B: #${orderId}`,
                    html: `< h1 > Nouvelle Commande de ${shipping.first_name} ${shipping.last_name}</h1 ><p>Total: MAD ${total.toFixed(2)}</p><p>Clinique: ${shipping.clinic_name || 'N/A'}</p><p>Ville: ${shipping.city}</p>`
                });

                return new Response(JSON.stringify({ success: true, id: orderId, total }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path === "/api/v1/dashboard/" && request.method === "GET") {
                const { results: orders } = await env.DB.prepare("SELECT * FROM \"order\" LIMIT 10").all();
                const stats = await env.DB.prepare("SELECT COUNT(*) as count, SUM(total_amount) as total FROM \"order\"").first();
                return new Response(JSON.stringify({ orders, stats }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }

            if (path.match(/\/api\/v1\/orders\/([^/]+)\/invoice/) && request.method === "GET") {
                const orderId = path.split("/")[4];
                const order = await env.DB.prepare("SELECT * FROM \"order\" WHERE id = ?").bind(orderId).first();
                if (!order) return new Response("Not Found", { status: 404, headers: corsHeaders });

                const items = await env.DB.prepare("SELECT oi.*, p.name FROM order_item oi JOIN product p ON oi.product_id = p.id WHERE oi.order_id = ?").bind(orderId).all();

                const cacheKey = `invoice-${orderId}.pdf`;
                try {
                    const cachedPdf = await env.STORAGE.get(cacheKey);
                    if (cachedPdf) {
                        return new Response(cachedPdf.body, {
                            headers: {
                                "Content-Type": "application/pdf",
                                "Content-Disposition": `inline; filename="Facture_${orderId}.pdf"`,
                                ...corsHeaders
                            }
                        });
                    }
                } catch (e) { console.error("R2 cache req error", e); }

                try {
                    const pdfDoc = await PDFDocument.create();
                    const page = pdfDoc.addPage([595.28, 841.89]);
                    const { width, height } = page.getSize();
                    const fontBold = await pdfDoc.embedFont(StandardFonts.HelveticaBold);
                    const fontRegular = await pdfDoc.embedFont(StandardFonts.Helvetica);

                    page.drawText('MediUnit - Facture Officielle', { x: 50, y: height - 50, size: 20, font: fontBold });
                    page.drawText(`Commande ID: #${orderId}`, { x: 50, y: height - 80, size: 12, font: fontRegular });
                    page.drawText(`Total: MAD ${order.total_amount}`, { x: 50, y: height - 100, size: 14, font: fontBold });

                    let y = height - 140;
                    page.drawText('Articles:', { x: 50, y, size: 12, font: fontBold });
                    y -= 20;

                    for (const item of items.results) {
                        page.drawText(`- ${item.name}(x${item.quantity})`, { x: 50, y, size: 10, font: fontRegular });
                        y -= 15;
                    }

                    const pdfBytes = await pdfDoc.save();
                    try {
                        await env.STORAGE.put(cacheKey, pdfBytes, {
                            httpMetadata: { contentType: "application/pdf" }
                        });
                    } catch (e) { console.error("R2 invoice put error", e); }

                    return new Response(pdfBytes, {
                        headers: { "Content-Type": "application/pdf", ...corsHeaders }
                    });
                } catch (e) {
                    return new Response("PDF Generation Error", { status: 500, headers: corsHeaders });
                }
            }

            if (path.match(/^\/api\/v1\/products\/([^/]+)$/) && request.method === "DELETE") {
                const productId = path.split("/")[4];
                await env.DB.prepare("DELETE FROM product WHERE id = ?").bind(productId).run();
                return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json", ...corsHeaders } });
            }
            // --------------------

            return new Response(JSON.stringify({ status: "ok", message: "MediUnit API JS" }), {
                headers: { "Content-Type": "application/json", ...corsHeaders }
            });
        } catch (e) {
            return new Response(JSON.stringify({ error: e.message }), {
                status: 500,
                headers: { "Content-Type": "application/json", ...corsHeaders }
            });
        }
    }
};
